//! Envelope-v3 bounded-step walks (Wave C / C4): a long multi-arm walk
//! suspends on hop-budget exhaustion with a serializable cursor and resumes
//! to the SAME answer as an unbounded walk — across any number of
//! suspensions, including suspensions INSIDE a user-helper frame. Cursors
//! fail closed everywhere: fingerprint pinning, exact key discipline,
//! unknown node ids, frame/helper mismatches.
//!
//! The synthetic program exercises every certified node kind on one spine:
//! Entry → certified foil fanout (Promise.all Fork/Fold over
//! loadUser/loadProfile) → merge → pass-through chain → user-helper call
//! (with its own long pass-through chain) → pass-through chain → template
//! Return. Unbounded oracle: `res:[ada:user|ada:profile]`.

use gg_walker_wasm::{
    run_envelope_bytes, run_program, run_program_bounded, Helpers, Topology, WalkOutcome,
    GG_CURSOR_KEY,
};
use serde_json::{json, Value};

/// Root topology: entry → Promise.all fork/fold → merge → t0..t7 →
/// dub(summary) → u0..u3 → return `res:${d}`.
fn root_topology() -> Value {
    let mut nodes = vec![
        json!({"id": "entry", "labels": ["Entry"], "properties": {}}),
        json!({"id": "fan", "labels": ["Statement"], "properties": {
            "callee": "Promise.all", "bind_pattern": "results", "branches": "2"
        }}),
        json!({"id": "b0", "labels": ["Branch", "PolyglotBridgeCall"], "properties": {
            "branch_index": "0", "callee": "loadUser",
            "foil_lowering": "Promise.all", "scheduler": "gnosis-foil"
        }}),
        json!({"id": "b1", "labels": ["Branch", "PolyglotBridgeCall"], "properties": {
            "branch_index": "1", "callee": "loadProfile",
            "foil_lowering": "Promise.all", "scheduler": "gnosis-foil"
        }}),
        json!({"id": "join", "labels": ["Join"], "properties": {
            "arity": "2", "bind_pattern": "results"
        }}),
        json!({"id": "merge", "labels": ["Statement"], "properties": {
            "callee": "merge", "bind": "summary"
        }}),
    ];
    let mut edges = vec![
        json!({"source_ids": ["entry"], "target_ids": ["fan"], "type": "Process", "properties": {}}),
        json!({"source_ids": ["fan"], "target_ids": ["b0", "b1"], "type": "Fork", "properties": {
            "foil_lowering": "Promise.all", "scheduler": "gnosis-foil"
        }}),
        json!({"source_ids": ["b0", "b1"], "target_ids": ["join"], "type": "Fold", "properties": {
            "foil_lowering": "Promise.all", "scheduler": "gnosis-foil"
        }}),
        json!({"source_ids": ["fan"], "target_ids": ["merge"], "type": "Process", "properties": {}}),
    ];
    let mut prev = "merge".to_string();
    for i in 0..8 {
        let id = format!("t{i}");
        nodes.push(json!({"id": id, "labels": ["TsBridgeCall"], "properties": {}}));
        edges.push(json!({"source_ids": [prev], "target_ids": [id], "type": "Process", "properties": {}}));
        prev = id;
    }
    nodes.push(json!({"id": "call_dub", "labels": ["Statement"], "properties": {
        "callee": "dub",
        "args": "[{\"kind\":\"ident\",\"name\":\"summary\"}]",
        "bind": "d"
    }}));
    edges.push(json!({"source_ids": [prev], "target_ids": ["call_dub"], "type": "Process", "properties": {}}));
    prev = "call_dub".to_string();
    for i in 0..4 {
        let id = format!("u{i}");
        nodes.push(json!({"id": id, "labels": ["TsBridgeCall"], "properties": {}}));
        edges.push(json!({"source_ids": [prev], "target_ids": [id], "type": "Process", "properties": {}}));
        prev = id;
    }
    nodes.push(json!({"id": "ret", "labels": ["Return"], "properties": {
        "expr": "{\"kind\":\"template\",\"parts\":[{\"kind\":\"text\",\"s\":\"res:\"},{\"kind\":\"expr\",\"e\":{\"kind\":\"ident\",\"name\":\"d\"}}]}"
    }}));
    edges.push(json!({"source_ids": [prev], "target_ids": ["ret"], "type": "Process", "properties": {}}));
    json!({"nodes": nodes, "edges": edges})
}

/// Helper `dub(s)`: entry → h0..h5 pass-through → return `[${s}]`.
fn dub_topology() -> Value {
    let mut nodes = vec![json!({"id": "dentry", "labels": ["Entry"], "properties": {
        "param_names": "[\"s\"]"
    }})];
    let mut edges = Vec::new();
    let mut prev = "dentry".to_string();
    for i in 0..6 {
        let id = format!("h{i}");
        nodes.push(json!({"id": id, "labels": ["TsBridgeCall"], "properties": {}}));
        edges.push(json!({"source_ids": [prev], "target_ids": [id], "type": "Process", "properties": {}}));
        prev = id;
    }
    nodes.push(json!({"id": "dret", "labels": ["Return"], "properties": {
        "expr": "{\"kind\":\"template\",\"parts\":[{\"kind\":\"text\",\"s\":\"[\"},{\"kind\":\"expr\",\"e\":{\"kind\":\"ident\",\"name\":\"s\"}},{\"kind\":\"text\",\"s\":\"]\"}]}"
    }}));
    edges.push(json!({"source_ids": [prev], "target_ids": ["dret"], "type": "Process", "properties": {}}));
    json!({"nodes": nodes, "edges": edges})
}

fn program() -> (Topology, Helpers) {
    let topology: Topology =
        serde_json::from_value(root_topology()).expect("root topology parses");
    let mut helpers = Helpers::new();
    helpers.insert(
        "dub".to_string(),
        serde_json::from_value(dub_topology()).expect("dub topology parses"),
    );
    (topology, helpers)
}

fn input() -> Value {
    json!({"userId": "ada"})
}

const ORACLE: &str = "res:[ada:user|ada:profile]";

fn cursor_field<'v>(cursor: &'v Value, key: &str) -> &'v Value {
    &cursor[GG_CURSOR_KEY][key]
}

#[test]
fn unbounded_walk_matches_the_oracle() {
    let (topology, helpers) = program();
    let out = run_program(&topology, &helpers, &input()).expect("unbounded walk");
    assert_eq!(out, Value::String(ORACLE.into()));
}

#[test]
fn bounded_walk_suspends_and_resumes_to_the_same_answer() {
    let (topology, helpers) = program();
    for budget in [1u64, 2, 3, 5, 7, 11] {
        let mut resumes = 0usize;
        let mut last_ordinal = 0u64;
        let mut cursor: Option<Value> = None;
        let final_value = loop {
            let outcome = run_program_bounded(
                &topology,
                &helpers,
                &input(),
                Some(budget),
                cursor.as_ref(),
            )
            .expect("bounded walk never declines on this program");
            match outcome {
                WalkOutcome::Complete(value) => break value,
                WalkOutcome::Suspended(next) => {
                    let ordinal = cursor_field(&next, "ordinal")
                        .as_u64()
                        .expect("cursor ordinal");
                    if resumes > 0 {
                        assert!(
                            ordinal > last_ordinal,
                            "ordinal must be strictly monotone across suspensions \
                             (budget {budget}: {last_ordinal} → {ordinal})"
                        );
                    }
                    last_ordinal = ordinal;
                    resumes += 1;
                    assert!(resumes < 1000, "walk must terminate");
                    cursor = Some(next);
                }
            }
        };
        assert_eq!(
            final_value,
            Value::String(ORACLE.into()),
            "budget {budget} must fold to the unbounded answer"
        );
        assert!(
            resumes > 0,
            "budget {budget} must actually suspend on this long walk"
        );
    }
}

#[test]
fn suspension_inside_a_helper_frame_carries_the_frame_stack() {
    let (topology, helpers) = program();
    // Root spine consumes 12 hops before entering `dub` (entry, fan, merge,
    // t0..t7, call_dub); budget 15 lands inside the helper's chain.
    let outcome = run_program_bounded(&topology, &helpers, &input(), Some(15), None)
        .expect("bounded walk");
    let WalkOutcome::Suspended(cursor) = outcome else {
        panic!("budget 15 must suspend inside the helper");
    };
    let frames = cursor_field(&cursor, "frames")
        .as_array()
        .expect("cursor frames");
    assert_eq!(frames.len(), 2, "root frame + helper frame: {cursor}");
    assert_eq!(frames[0]["t"], json!("root"));
    assert_eq!(frames[0]["nodeId"], json!("call_dub"));
    assert_eq!(frames[1]["t"], json!("helper:dub"));
    // The helper frame carries its bound parameter — serializable state.
    assert_eq!(
        frames[1]["scope"]["s"],
        json!("ada:user|ada:profile"),
        "helper scope must carry the bound parameter: {cursor}"
    );

    // Resume UNBOUNDED: fast-forwards through the in-flight call and folds
    // to the oracle.
    let outcome = run_program_bounded(&topology, &helpers, &input(), None, Some(&cursor))
        .expect("resume");
    assert_eq!(outcome, WalkOutcome::Complete(Value::String(ORACLE.into())));
}

#[test]
fn budget_zero_suspends_without_progress_and_without_ordinal_drift() {
    let (topology, helpers) = program();
    let WalkOutcome::Suspended(first) =
        run_program_bounded(&topology, &helpers, &input(), Some(0), None).expect("bounded")
    else {
        panic!("budget 0 must suspend immediately");
    };
    assert_eq!(cursor_field(&first, "ordinal"), &json!(0));
    assert_eq!(cursor_field(&first, "nodeId"), &json!("entry"));

    // Resuming with budget 0 makes no progress and must NOT advance ordinal.
    let WalkOutcome::Suspended(second) =
        run_program_bounded(&topology, &helpers, &input(), Some(0), Some(&first))
            .expect("bounded resume")
    else {
        panic!("budget 0 resume must suspend again");
    };
    assert_eq!(first, second, "no progress ⇒ identical cursor");
}

#[test]
fn cursors_fail_closed() {
    let (topology, helpers) = program();
    let WalkOutcome::Suspended(cursor) =
        run_program_bounded(&topology, &helpers, &input(), Some(5), None).expect("bounded")
    else {
        panic!("budget 5 must suspend");
    };

    // Tampered fingerprint.
    let mut tampered = cursor.clone();
    tampered[GG_CURSOR_KEY]["topo"] = json!("0000000000000000");
    let err = run_program_bounded(&topology, &helpers, &input(), None, Some(&tampered))
        .unwrap_err();
    assert!(err.0.contains("fingerprint"), "{err}");

    // Resume against a DIFFERENT program (extra pass-through node) — the
    // fingerprint pins the program, not just node ids.
    let mut altered_json = root_topology();
    altered_json["nodes"]
        .as_array_mut()
        .unwrap()
        .push(json!({"id": "extra", "labels": ["TsBridgeCall"], "properties": {}}));
    let altered: Topology = serde_json::from_value(altered_json).unwrap();
    let err = run_program_bounded(&altered, &helpers, &input(), None, Some(&cursor))
        .unwrap_err();
    assert!(err.0.contains("fingerprint"), "{err}");

    // Unknown node id.
    let mut bad = cursor.clone();
    bad[GG_CURSOR_KEY]["nodeId"] = json!("nope");
    bad[GG_CURSOR_KEY]["frames"][0]["nodeId"] = json!("nope");
    let err =
        run_program_bounded(&topology, &helpers, &input(), None, Some(&bad)).unwrap_err();
    assert!(err.0.contains("unknown node id"), "{err}");

    // Unknown cursor key.
    let mut bad = cursor.clone();
    bad[GG_CURSOR_KEY]["extra"] = json!(1);
    assert!(run_program_bounded(&topology, &helpers, &input(), None, Some(&bad)).is_err());

    // Inner/outer disagreement.
    let mut bad = cursor.clone();
    bad[GG_CURSOR_KEY]["nodeId"] = json!("ret");
    let err =
        run_program_bounded(&topology, &helpers, &input(), None, Some(&bad)).unwrap_err();
    assert!(err.0.contains("disagrees"), "{err}");

    // Frames must be non-empty.
    let mut bad = cursor.clone();
    bad[GG_CURSOR_KEY]["frames"] = json!([]);
    assert!(run_program_bounded(&topology, &helpers, &input(), None, Some(&bad)).is_err());

    // A frame tag naming an unknown helper.
    let mut bad = cursor.clone();
    bad[GG_CURSOR_KEY]["frames"][0]["t"] = json!("helper:ghost");
    assert!(run_program_bounded(&topology, &helpers, &input(), None, Some(&bad)).is_err());

    // Not an object / wrong wrapper key.
    assert!(
        run_program_bounded(&topology, &helpers, &input(), None, Some(&json!("x"))).is_err()
    );
    assert!(run_program_bounded(
        &topology,
        &helpers,
        &input(),
        None,
        Some(&json!({"cursor": {}}))
    )
    .is_err());
}

#[test]
fn envelope_v3_rides_run_envelope_bytes() {
    let envelope = json!({
        "topology": root_topology(),
        "helpers": {"dub": dub_topology()},
        "input": input(),
        "budget": 6,
    });
    let out = run_envelope_bytes(serde_json::to_string(&envelope).unwrap().as_bytes())
        .expect("bounded envelope runs");
    let cursor: Value = serde_json::from_str(&out).expect("cursor JSON");
    assert!(
        cursor.get(GG_CURSOR_KEY).is_some(),
        "bounded envelope must answer with a cursor: {out}"
    );

    // Resume through the envelope — walk to completion unbounded.
    let resume_envelope = json!({
        "topology": root_topology(),
        "helpers": {"dub": dub_topology()},
        "input": input(),
        "resume": cursor,
    });
    let out = run_envelope_bytes(
        serde_json::to_string(&resume_envelope).unwrap().as_bytes(),
    )
    .expect("resume envelope runs");
    assert_eq!(out, serde_json::to_string(ORACLE).unwrap(), "{out}");
}

#[test]
fn envelope_compatibility_and_fail_closure() {
    // v1/v2 exact behavior unchanged: unknown keys still decline.
    assert!(run_envelope_bytes(
        br#"{"topology":{"nodes":[],"edges":[]},"input":{},"extra":1}"#
    )
    .is_err());
    // budget must be a non-negative integer.
    for bad in [json!(-1), json!(1.5), json!("7"), json!(null)] {
        let envelope = json!({
            "topology": root_topology(),
            "helpers": {"dub": dub_topology()},
            "input": input(),
            "budget": bad,
        });
        let err = run_envelope_bytes(
            serde_json::to_string(&envelope).unwrap().as_bytes(),
        )
        .unwrap_err();
        assert!(err.0.contains("budget"), "{err}");
    }
    // A v3 envelope without budget/resume is exactly v2.
    let envelope = json!({
        "topology": root_topology(),
        "helpers": {"dub": dub_topology()},
        "input": input(),
    });
    let out = run_envelope_bytes(serde_json::to_string(&envelope).unwrap().as_bytes())
        .expect("v2 envelope runs");
    assert_eq!(out, serde_json::to_string(ORACLE).unwrap());
}
